import android.content.Context;
import android.content.SharedPreferences;
import android.util.Base64;

public class LoginManager {
    private static final String PREFS_NAME = "user_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_AUTH_TOKEN = "auth_token";

    private SharedPreferences sharedPreferences;

    public LoginManager(Context context) {
        sharedPreferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    public void saveCredentials(String email, String authToken) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(KEY_EMAIL, email);
        editor.putString(KEY_AUTH_TOKEN, encrypt(authToken));
        editor.apply();
    }

    public String getEmail() {
        return sharedPreferences.getString(KEY_EMAIL, null);
    }

    public String getAuthToken() {
        String encryptedToken = sharedPreferences.getString(KEY_AUTH_TOKEN, null);
        return encryptedToken != null ? decrypt(encryptedToken) : null;
    }

    private String encrypt(String data) {
        // Simple Base64 encoding for demonstration purposes
        return Base64.encodeToString(data.getBytes(), Base64.DEFAULT);
    }

    private String decrypt(String data) {
        // Simple Base64 decoding for demonstration purposes
        return new String(Base64.decode(data, Base64.DEFAULT));
    }
}